9	
10	const MAIN_BASE_PREMIUMS: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune"]);
18	const COMPONENT_SINGLE_PREMIUM = 25;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	const COMPONENT_BLOCK_SIZE = 3;
21	
22	const CURSED_SURCHARGE = 0.5;
23	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
24	const HIGH_ENCHANTMENT_THRESHOLD = 5;
25	
26	const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);
27	
28	const componentsPremium = (count: number): number => {
29	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
30	  const singles = count % COMPONENT_BLOCK_SIZE;
31	  return blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_SINGLE_PREMIUM;
32	};
33	
34	const itemSurcharge = (item: Item): number => {
35	  let surcharge = 0;
36	  if (item.cursed) surcharge += CURSED_SURCHARGE;
37	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
38	    surcharge += HIGH_ENCHANTMENT_SURCHARGE;
39	  }
40	  return surcharge;
41	};
42	
43	const itemPremium = (item: Item): number => {
44	  const base = isComponent(item.type)
45	    ? COMPONENT_SINGLE_PREMIUM
46	    : MAIN_BASE_PREMIUMS[item.type];
47	  return base * (1 + itemSurcharge(item));
48	};
49	
50	const itemsBasePremium = (items: Item[]): number => {
51	  const mainItems = items.filter((item) => !isComponent(item.type));
52	  const components = items.filter((item) => isComponent(item.type));
53	  const mainTotal = mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
54	  return mainTotal + componentsPremium(components.length);
55	};
56	
57	const roundUp = (value: number): number => {
58	  const epsilon = 1e-9;
59	  return Math.ceil(value - epsilon);
60	};
61	
62	const FIRST_INSURANCE_SURCHARGE = 0.1;
63	const SUBSEQUENT_CONTRACT_DISCOUNT = 0.15;
64	const LOYALTY_DISCOUNT = 0.2;
65	const LOYALTY_THRESHOLD_YEARS = 2;
66	const PROCESSING_FEE = 5;
67	
68	type Customer = { yearsWithMHPCO: number };
69	
70	const customerModifier = (customer: Customer, isFirstQuote: boolean): number => {
71	  let modifier = isFirstQuote
72	    ? FIRST_INSURANCE_SURCHARGE
73	    : -SUBSEQUENT_CONTRACT_DISCOUNT;
74	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
75	    modifier -= LOYALTY_DISCOUNT;
76	  }
77	  return modifier;
78	};
79	
80	export const run = (input: Input): unknown => {
81	  let quoteCount = 0;
82	  const results = input.steps.map((step) => {
83	    const isFirstQuote = quoteCount === 0;
84	    quoteCount += 1;
85	    const base = itemsBasePremium(step.items);
86	    const adjusted = base * (1 + customerModifier(input.customer, isFirstQuote));
87	    const premium = roundUp(adjusted) + PROCESSING_FEE;
88	    return { premium };
89	  });
90	  return { results };
91	};
