const quoteStep = (
  items: Item[],
  customer: Customer,
  isFirstQuote: boolean,
): { premium: number } => {
  const base = itemsBasePremium(items);
  const adjusted = base * (1 + customerModifier(customer, isFirstQuote));
  return { premium: roundUp(adjusted) + PROCESSING_FEE };
};

export const run = (input: Input): unknown => {
  let quoteCount = 0;
  const results = input.steps.map((step) => {
    const isFirstQuote = quoteCount === 0;
    quoteCount += 1;
    return quoteStep(step.items, input.customer, isFirstQuote);
  });
  return { results };
};
